class Repository:
    def __init__(self):
        self.users = {}
        self.orders = {}
        self._uid = 1
        self._oid = 1

    def next_user_id(self):
        uid = self._uid; self._uid += 1; return uid

    def next_order_id(self):
        oid = self._oid; self._oid += 1; return oid

    def save_user(self, u): self.users[u.id] = u
    def save_order(self, o): self.orders[o.id] = o

